/** Cloud with arrow up - for empty slot. Uses unique IDs per instance so multiple icons render correctly. */
export const CloudUploadIcon = ({
  width = 40,
  height = 40,
}: IconProps = {}) => {
  const uid = React.useId().replace(/:/g, "");
  const maskId = `cloud-mask-${uid}`;
  const patternId = `cloud-pattern-${uid}`;
  const imageId = `cloud-image-${uid}`;
  return (
    <svg
      width={width}
      height={height}
      viewBox="0 0 40 40"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      xmlnsXlink="http://www.w3.org/1999/xlink"
    >
      <mask
        id={maskId}
        style={{ maskType: "alpha" }}
        maskUnits="userSpaceOnUse"
        x="0"
        y="0"
        width="40"
        height="40"
      >
        <rect width="40" height="40" fill={`url(#${patternId})`} />
      </mask>
      <g mask={`url(#${maskId})`}>
        <rect width="40" height="40" fill="#758599" />
      </g>
      <defs>
        <pattern
          id={patternId}
          patternContentUnits="objectBoundingBox"
          width="1"
          height="1"
        >
          <use xlinkHref={`#${imageId}`} transform="scale(0.0078125)" />
        </pattern>
        <image
          id={imageId}
          width="128"
          height="128"
          preserveAspectRatio="none"
          xlinkHref="data:image/png;base64,"
        />
      </defs>
    </svg>
  );
};

